// @ts-nocheck
// ─── AQA GCSE English Language Mock Exam Papers ─────────────────────────────
// 15 Paper 1 + 15 Paper 2 = 30 papers total

import type { MockExamPaper } from './mock-exams'

// ─── Helper: creates a standard P1 paper from config ────────────────────────

interface P1Config {
  set: string
  source: string
  extract: string
  q1TrueStatements: string
  q1Options: string
  q1Answers45: string
  q1Answers67: string
  q2Focus: string
  q2Text: string
  q2Answer45: string
  q2Answer67: string
  q3Text: string
  q3Answer45: string
  q3Answer67: string
  q4Focus: string
  q4Statement: string
  q4Text: string
  q4Answer45: string
  q4Answer67: string
  q5ImageDesc: string
  q5NarrativePrompt: string
}

function makeP1(n: number, c: P1Config): MockExamPaper {
  const nn = String(n).padStart(2, '0')
  return {
    id: `aqa-p1-${nn}`,
    board: 'AQA',
    paperNumber: 1,
    title: 'AQA Paper 1',
    subtitle: `Explorations in Creative Reading and Writing — Set ${n}`,
    code: '8700/1',
    totalTimeMinutes: 105,
    totalMarks: 80,
    sections: [
      {
        id: `aqa-p1-${nn}-reading`,
        title: 'Section A: Reading',
        description: `Read the extract below carefully. Then answer all the questions in this section.\n\nSource: ${c.source}`,
        totalMarks: 40,
        suggestedTimeMinutes: 60,
        questions: [
          {
            id: `aqa-p1-${nn}-q1`,
            questionNumber: 1,
            questionText: `Read again the first part of the source, ${c.q1TrueStatements}\n\nChoose four statements below which are TRUE.\n\n${c.q1Options}`,
            marks: 4,
            suggestedTimeMinutes: 5,
            questionType: 'multiple-choice',
            extract: c.extract,
            extractSource: c.source,
            modelAnswers: {
              'Grade 4-5': c.q1Answers45,
              'Grade 6-7': c.q1Answers67,
            },
            markScheme: [
              '1 mark for each correct answer',
              'Maximum 4 marks',
              'No marks for incorrect selections beyond four',
            ],
          },
          {
            id: `aqa-p1-${nn}-q2`,
            questionNumber: 2,
            questionText: `Look in detail at the extract ${c.q2Focus}\n\nHow does the writer use language here ${c.q2Text}\n\nYou could include the writer's choice of:\n- words and phrases\n- language features and techniques\n- sentence forms.`,
            marks: 8,
            suggestedTimeMinutes: 10,
            questionType: 'analysis',
            extract: c.extract,
            extractSource: c.source,
            modelAnswers: {
              'Grade 4-5': c.q2Answer45,
              'Grade 6-7': c.q2Answer67,
            },
            markScheme: [
              'Identifies relevant language features and techniques',
              'Analyses the effect of specific words and phrases',
              'Comments on how language creates mood/atmosphere/meaning',
              'Uses subject terminology accurately',
              'Top band: sophisticated, conceptualised analysis of language',
            ],
          },
          {
            id: `aqa-p1-${nn}-q3`,
            questionNumber: 3,
            questionText: `You now need to think about the whole of the source.\n\n${c.q3Text}\n\nYou could write about:\n- what the writer focuses your attention on at the beginning\n- how and why the writer changes this focus as the extract develops\n- any other structural features that interest you.`,
            marks: 8,
            suggestedTimeMinutes: 10,
            questionType: 'analysis',
            extract: c.extract,
            extractSource: c.source,
            modelAnswers: {
              'Grade 4-5': c.q3Answer45,
              'Grade 6-7': c.q3Answer67,
            },
            markScheme: [
              'Comments on structural features and their effects',
              'Analyses shifts in focus, perspective, or pace',
              'Considers how structure shapes meaning for the reader',
              'Uses structural terminology appropriately',
              'Top band: perceptive, detailed analysis of structure',
            ],
          },
          {
            id: `aqa-p1-${nn}-q4`,
            questionNumber: 4,
            questionText: `Focus this part of your answer on the second half of the source, ${c.q4Focus}\n\nA student said: "${c.q4Statement}"\n\nTo what extent do you agree?\n\nIn your response, you could:\n- consider your own impressions of the text\n- evaluate how the writer has created these impressions\n- support your response with references to the text.`,
            marks: 20,
            suggestedTimeMinutes: 22,
            questionType: 'evaluation',
            extract: c.extract,
            extractSource: c.source,
            modelAnswers: {
              'Grade 4-5': c.q4Answer45,
              'Grade 6-7': c.q4Answer67,
            },
            markScheme: [
              'Evaluates critically with a clear personal response',
              'Shows a sustained and developed argument',
              'Selects and analyses appropriate textual evidence',
              'Considers alternative interpretations where relevant',
              'Top band: evaluative, critical, conceptualised response',
            ],
          },
        ],
      },
      {
        id: `aqa-p1-${nn}-writing`,
        title: 'Section B: Writing',
        description: 'You are advised to spend about 45 minutes on this section. Write in full sentences. You are reminded of the need to plan your answer. You should leave enough time to check your work at the end.',
        totalMarks: 40,
        suggestedTimeMinutes: 45,
        questions: [
          {
            id: `aqa-p1-${nn}-q5`,
            questionNumber: 5,
            questionText: `You are going to enter a creative writing competition.\n\nYour entry will be judged by a panel of published authors.\n\nEither:\nWrite a description suggested by this picture: [${c.q5ImageDesc}]\n\nOr:\n${c.q5NarrativePrompt}\n\n(24 marks for content and organisation / 16 marks for technical accuracy)`,
            marks: 40,
            suggestedTimeMinutes: 45,
            questionType: 'creative-writing',
            modelAnswers: {
              'Grade 4-5': 'A clear and engaging piece of creative writing that uses some descriptive techniques (simile, metaphor, sensory detail), has a clear structure with distinct paragraphs, includes varied vocabulary, and demonstrates generally accurate spelling and punctuation with some variety in sentence structure.',
              'Grade 6-7': 'A compelling piece that crafts a controlled atmosphere through sustained sensory detail, uses varied and ambitious vocabulary, demonstrates conscious structural choices, employs a range of sentence forms for effect, and shows consistent accuracy in spelling, punctuation, and grammar with some sophisticated constructions.',
              'Grade 8-9': 'An assured, crafted piece that creates a vivid, immersive experience through precise, original imagery, demonstrates sophisticated structural control, uses an extensive vocabulary with precise word choices, employs varied sentence structures with complete control, and shows technical virtuosity in punctuation.',
            },
            markScheme: [
              'AO5 Content & Organisation (24 marks): Communication, tone, style, register',
              'AO5: Organisation of ideas with structural/grammatical features',
              'AO6 Technical Accuracy (16 marks): Sentence demarcation and punctuation range',
              'AO6: Spelling including ambitious vocabulary',
              'AO6: Variety of sentence forms for effect',
            ],
          },
        ],
      },
    ],
  }
}

// ─── Helper: creates a standard P2 paper from config ────────────────────────

interface P2Config {
  sourceAText: string
  sourceARef: string
  sourceBText: string
  sourceBRef: string
  q1Text: string
  q1Answer45: string
  q2Text: string
  q2Answer45: string
  q2Answer67: string
  q3Text: string
  q3Answer45: string
  q3Answer67: string
  q4Text: string
  q4Answer45: string
  q4Answer67: string
  q5Text: string
}

function makeP2(n: number, c: P2Config): MockExamPaper {
  const nn = String(n).padStart(2, '0')
  const combinedExtract = `Source A:\n${c.sourceAText}\n\nSource B:\n${c.sourceBText}`
  const combinedRef = `Source A: ${c.sourceARef} | Source B: ${c.sourceBRef}`
  return {
    id: `aqa-p2-${nn}`,
    board: 'AQA',
    paperNumber: 2,
    title: 'AQA Paper 2',
    subtitle: `Writers' Viewpoints and Perspectives — Set ${n}`,
    code: '8700/2',
    totalTimeMinutes: 105,
    totalMarks: 80,
    sections: [
      {
        id: `aqa-p2-${nn}-reading`,
        title: 'Section A: Reading',
        description: `Read Source A and Source B carefully. Then answer all the questions in this section.\n\nSource A: ${c.sourceARef}\nSource B: ${c.sourceBRef}`,
        totalMarks: 40,
        suggestedTimeMinutes: 60,
        questions: [
          {
            id: `aqa-p2-${nn}-q1`,
            questionNumber: 1,
            questionText: c.q1Text,
            marks: 4,
            suggestedTimeMinutes: 5,
            questionType: 'multiple-choice',
            extract: combinedExtract,
            extractSource: combinedRef,
            modelAnswers: {
              'Grade 4-5': c.q1Answer45,
            },
            markScheme: [
              '1 mark for each correct answer',
              'Maximum 4 marks',
            ],
          },
          {
            id: `aqa-p2-${nn}-q2`,
            questionNumber: 2,
            questionText: c.q2Text,
            marks: 8,
            suggestedTimeMinutes: 10,
            questionType: 'summary',
            extract: combinedExtract,
            extractSource: combinedRef,
            modelAnswers: {
              'Grade 4-5': c.q2Answer45,
              'Grade 6-7': c.q2Answer67,
            },
            markScheme: [
              'Must reference both sources',
              'Identifies clear differences and/or similarities',
              'Uses evidence from both texts',
              'Synthesises rather than alternates between texts',
              'Infers beyond surface-level details',
            ],
          },
          {
            id: `aqa-p2-${nn}-q3`,
            questionNumber: 3,
            questionText: c.q3Text,
            marks: 12,
            suggestedTimeMinutes: 15,
            questionType: 'analysis',
            extract: `Source A:\n${c.sourceAText}`,
            extractSource: c.sourceARef,
            modelAnswers: {
              'Grade 4-5': c.q3Answer45,
              'Grade 6-7': c.q3Answer67,
            },
            markScheme: [
              'Analyses language techniques in detail',
              'Comments on the effect of specific words and phrases',
              'Considers how language positions the reader',
              'Uses subject terminology accurately',
              'Top band: perceptive, detailed, conceptualised analysis',
            ],
          },
          {
            id: `aqa-p2-${nn}-q4`,
            questionNumber: 4,
            questionText: c.q4Text,
            marks: 16,
            suggestedTimeMinutes: 20,
            questionType: 'comparison',
            extract: combinedExtract,
            extractSource: combinedRef,
            modelAnswers: {
              'Grade 4-5': c.q4Answer45,
              'Grade 6-7': c.q4Answer67,
            },
            markScheme: [
              'Compares attitudes from both sources throughout',
              'Analyses methods used by both writers',
              'Uses evidence from both texts',
              'Shows clear understanding of different perspectives',
              'Top band: perceptive, detailed comparison with sustained critical voice',
            ],
          },
        ],
      },
      {
        id: `aqa-p2-${nn}-writing`,
        title: 'Section B: Writing',
        description: 'You are advised to spend about 45 minutes on this section. Write in full sentences. You are reminded of the need to plan your answer.',
        totalMarks: 40,
        suggestedTimeMinutes: 45,
        questions: [
          {
            id: `aqa-p2-${nn}-q5`,
            questionNumber: 5,
            questionText: c.q5Text,
            marks: 40,
            suggestedTimeMinutes: 45,
            questionType: 'transactional-writing',
            modelAnswers: {
              'Grade 4-5': 'A clear argumentative piece that addresses the topic directly, uses some persuasive devices (rhetorical questions, direct address), has a clear structure with introduction, body paragraphs, and conclusion, and demonstrates generally accurate spelling and punctuation.',
              'Grade 6-7': 'A well-crafted argument that engages with the topic critically, uses a range of rhetorical techniques fluently, deploys evidence and examples effectively, matches the required register, and demonstrates consistent technical accuracy with ambitious vocabulary.',
              'Grade 8-9': 'A compelling, assured argument that offers a nuanced, sophisticated perspective, crafts a distinctive voice appropriate to the form, deploys rhetorical strategies with precision, uses counter-argument effectively, and demonstrates extensive vocabulary with technical virtuosity throughout.',
            },
            markScheme: [
              'AO5 (24 marks): Clear, effective communication matched to form, purpose, audience',
              'AO5: Structured argument with coherent paragraphing',
              'AO6 (16 marks): Accurate sentence demarcation',
              'AO6: Range of punctuation used effectively',
              'AO6: Accurate spelling of ambitious vocabulary',
            ],
          },
        ],
      },
    ],
  }
}

